import{_ as a,o as t,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const y=JSON.parse('{"title":"31. Salary Packaging","description":"","frontmatter":{"title":"31. Salary Packaging","eba":"Mental Health Services 2024-2028","topics":["wages","salary-packaging","preliminary"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/wages/31-salary-packaging.md","filePath":"ebas/mental-health/common-terms/wages/31-salary-packaging.md"}'),n={name:"ebas/mental-health/common-terms/wages/31-salary-packaging.md"};function s(l,e,i,p,c,h){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_31-salary-packaging" tabindex="-1">31. Salary Packaging <a class="header-anchor" href="#_31-salary-packaging" aria-label="Permalink to &quot;31. Salary Packaging&quot;">​</a></h1><p><strong>31.1</strong> An Employee may elect to salary package the current salary specified in Appendix 2 in accordance with the Employer’s policy provided that the Employer&#39;s policy is consistent with the guidelines published by the Australian Tax Office.</p><p><strong>31.2</strong> The Employee will compensate the Employer from within their salary for any Fringe Benefits Tax (FBT) incurred as a consequence of the Employee&#39;s salary packaging arrangements. Where the Employee chooses not to pay any of the costs associated with their salary packaging, the Employer may cease the Employee&#39;s salary packaging arrangements.</p><p><strong>31.3</strong> The Employee may elect to convert the amount packaged to salary for any reason, including where salary packaging ceases to be an advantage to the Employee because of subsequent changes to FBT legislation. Any costs associated with the conversion to salary shall be borne by the Employee and the Employer shall not be liable to make up any benefit lost as a consequence of an Employee&#39;s decision to convert to salary.</p><p><strong>31.4</strong> Where an overpayment to the salary packaging provider occurs as a result of Employer error, the Employer will refund the overpayment to the Employee and recover the money from the provider. Where all or part of the overpayment is subsequently refunded to the Employee by the provider, the Employer and Employee will take all reasonable steps to reach agreement on an appropriate resolution to:</p><p><strong>(a)</strong> address the repayment being made more than once; and</p><p><strong>(b)</strong> ensure that the Employee is neither advantaged nor disadvantaged as a result of the overpayment, provided that if agreement cannot be reached, the matter will be resolved in accordance with 22(Dispute Resolution Procedure).</p><p><strong>31.5</strong> The Employee will be responsible for all costs associated with the administration of their salary packaging arrangements, provided that such costs shall be confined to reasonable commercial charges as levied directly by the external salary packaging provider and/or in-house payroll services (as applicable), as varied from time to time.</p><p><strong>31.6</strong> Employees who are considering salary packaging ought to seek independent financial advice. The Employer will not be held responsible in any way for the cost or outcome of any such advice and any costs associated with salary packaging shall be paid for by the Employee.</p><p><strong>31.7</strong> Superannuation contributions paid by the Employer into an approved fund will be calculated on the Employee’s pre-packaged rate of pay.</p><p>Plain language terms: salary sacrifice, packaging, novated lease.</p>',11)])])}const m=a(n,[["render",s]]);export{y as __pageData,m as default};
